27	
28	void riscv_nn_activate_s8(q7_t * in_out, uint32_t size, uint16_t int_bits, riscv_nn_activation_fun act_fun)
29	{
30	#ifdef ENA_EMPTY_FUN
31	    //empty body
32	#else
33	    uint16_t shift_size = 3 - int_bits;
34	    const q7_t *lookup_table;
35	    switch (act_fun)
36	    {
37	    case NN_SIGMOID:
38	        lookup_table = sigmoidTable_q7;
39	        break;
40	    case NN_TANH:
41	    default:
42	        lookup_table = tanhTable_q7;
43	        break;
44	    }
45	
46	#if defined(ENA_VEC_ISA) && ((NDS_VEC_RVV_VERSION == 80) || defined(ENA_VEC_ISA_STRIDE_LS)) && 0
47	    long vl;
48	    //index load instructions' performance is not good as vrgather; thus, we
49	    //should use the vrgather algorithm first
50	    while(size > 0)
51	    {
52	        NDS_VEC_VSETVLI(vl, size, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
53	        NDS_VEC_VLB_V(NDS_VEC_V0, in_out);
54	        NDS_VEC_VSRA_VX(NDS_VEC_V0, NDS_VEC_V0, shift_size);
55	        //Note. vector index load instrunctions expect the index to be unsigned
56	        NDS_VEC_VLXB_V(NDS_VEC_V8, lookup_table, NDS_VEC_V0);
57	        NDS_VEC_VSB_V(NDS_VEC_V8, in_out);
58	        in_out += vl;
59	        size -= vl;
60	    }
61	#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION == 80)    //only for VLEN=512
62	    long vl;
63	
64	    //load lookup_table into registers
65	    NDS_VEC_VSETVLI(vl, 256, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);  //lookup_table size is 256
66	    NDS_VEC_VLB_V(NDS_VEC_V0, lookup_table);    //v0~v3
67	
68	    while(size > 0)
69	    {
70	        NDS_VEC_VSETVLI(vl, size, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
71	        NDS_VEC_VLB_V(NDS_VEC_V4, in_out);
72	        NDS_VEC_VSRA_VX(NDS_VEC_V4, NDS_VEC_V4, shift_size);
73	        NDS_VEC_VRGATHER_VV(NDS_VEC_V8, NDS_VEC_V0, NDS_VEC_V4);
74	        NDS_VEC_VSB_V(NDS_VEC_V8, in_out);
75	        in_out += vl;
76	        size -= vl;
77	    }
78	#elif defined(ENA_VEC_ISA) && defined(ENA_VEC_INTRINSIC)
79	    long vl;
80	    long vlenb = NDS_VEC_CSR_GET_VLENB();
81	    long size2 = size;
82	    if(vlenb >= 64)     //for VLEN>=512
83	    {
84	        //load lookup_table into registers
85	        vl = __riscv_vsetvl_e8m4(256);    //lookup_table size is 256
86	        vint8m4_t vLookup_table = __riscv_vle8_v_i8m4(lookup_table, vl);
87	
88	        while(size2 >= 512)
89	        {
90	            vl = __riscv_vsetvl_e8m8(size2);
91	            vint8m8_t vIn = __riscv_vle8_v_i8m8(in_out, vl);
92	            vint8m8_t vIdx_i8 = __riscv_vsra(vIn, shift_size, vl);
93	            vl = __riscv_vsetvl_e8m4(size2);
94	            vint8m4_t vIdx_i8_part1 = __riscv_vget_i8m4(vIdx_i8, 0);
95	            vint8m4_t vIdx_i8_part2 = __riscv_vget_i8m4(vIdx_i8, 1);
96	            vuint8m4_t vIdx_u8_part1 = __riscv_vreinterpret_u8m4(vIdx_i8_part1);
97	            vuint8m4_t vIdx_u8_part2 = __riscv_vreinterpret_u8m4(vIdx_i8_part2);
98	            vint8m4_t vOut_part1 = __riscv_vrgather(vLookup_table, vIdx_u8_part1, vl);
99	            vint8m4_t vOut_part2 = __riscv_vrgather(vLookup_table, vIdx_u8_part2, vl);
100	            vint8m8_t vOut = __riscv_vundefined_i8m8();
101	            vOut = __riscv_vset(vOut, 0, vOut_part1);
102	            vOut = __riscv_vset(vOut, 1, vOut_part2);
103	            vl = __riscv_vsetvl_e8m8(size2);
104	            __riscv_vse8(in_out, vOut, vl);
105	            in_out += vl;
106	            size2 -= vl;
107	        }
108	        while(size2 > 0)
109	        {
110	            vl = __riscv_vsetvl_e8m4(size2);
111	            vint8m4_t vIn = __riscv_vle8_v_i8m4(in_out, vl);
112	            vint8m4_t vIdx_i8 = __riscv_vsra(vIn, shift_size, vl);
113	            vuint8m4_t vIdx_u8 = __riscv_vreinterpret_u8m4(vIdx_i8);
114	            vint8m4_t vOut = __riscv_vrgather(vLookup_table, vIdx_u8, vl);
115	            __riscv_vse8(in_out, vOut, vl);
116	
117	            in_out += vl;
118	            size2 -= vl;
119	        }
120	    }
121	    else if(vlenb == 32)     //for VLEN=256
122	    {
123	        //load lookup_table into registers
124	        vl = __riscv_vsetvl_e8m8(256);    //lookup_table size is 256
125	        vint8m8_t vLookup_table = __riscv_vle8_v_i8m8(lookup_table, vl);
126	        while(size2 > 0)
127	        {
128	            vl = __riscv_vsetvl_e8m8(size2);
129	            vint8m8_t vIn = __riscv_vle8_v_i8m8(in_out, vl);
130	            vint8m8_t vIdx_i8 = __riscv_vsra(vIn, shift_size, vl);
131	            vuint8m8_t vIdx_u8 = __riscv_vreinterpret_u8m8(vIdx_i8);
132	            vint8m8_t vOut = __riscv_vrgather(vLookup_table, vIdx_u8, vl);
133	            __riscv_vse8(in_out, vOut, vl);
134	
135	            in_out += vl;
136	            size2 -= vl;
137	        }
138	    }
139	    else    //general algorithm for any VLEN
140	    {
141	        while(size2 > 0)
142	        {
143	            vl = __riscv_vsetvl_e8m8(size2);
144	            vint8m8_t vIn = __riscv_vle8_v_i8m8(in_out, vl);
145	            vint8m8_t vIdx_i8 = __riscv_vsra(vIn, shift_size, vl);
146	            //Note. vector index load instrunctions expect the index to be unsigned
147	            vuint8m8_t vIdx_u8 = __riscv_vreinterpret_u8m8(vIdx_i8);
148	            vint8m8_t vOut = __riscv_vluxei8(lookup_table, vIdx_u8, vl);
149	            __riscv_vse8(in_out, vOut, vl);
150

150	
151	            in_out += vl;
152	            size2 -= vl;
153	        }
154	    }
155	#elif defined(ENA_VEC_ISA)
156	    long vl;
157	    long vlenb = NDS_VEC_CSR_GET_VLENB();
158	    long size2 = size;
159	
160	    if(vlenb >= 64)     //for VLEN>=512
161	    {
162	        //load lookup_table into registers
163	        NDS_VEC_VSETVLI(vl, 256, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);  //lookup_table size is 256
164	        NDS_VEC_VLB_V(NDS_VEC_V0, lookup_table);    //v0~v3
165	
166	        while(size2 >= 512)
167	        {
168	            NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
169	            NDS_VEC_VLB_V(NDS_VEC_V16, in_out);
170	            NDS_VEC_VSRA_VX(NDS_VEC_V16, NDS_VEC_V16, shift_size);
171	            NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
172	            NDS_VEC_VRGATHER_VV(NDS_VEC_V8, NDS_VEC_V0, NDS_VEC_V16);
173	            NDS_VEC_VRGATHER_VV(NDS_VEC_V12, NDS_VEC_V0, NDS_VEC_V20);
174	            NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
175	            NDS_VEC_VSB_V(NDS_VEC_V8, in_out);
176	            in_out += vl;
177	            size2 -= vl;
178	        }
179	        while(size2 > 0)
180	        {
181	            NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
182	            NDS_VEC_VLB_V(NDS_VEC_V16, in_out);
183	            NDS_VEC_VSRA_VX(NDS_VEC_V16, NDS_VEC_V16, shift_size);
184	            NDS_VEC_VRGATHER_VV(NDS_VEC_V8, NDS_VEC_V0, NDS_VEC_V16);
185	            NDS_VEC_VSB_V(NDS_VEC_V8, in_out);
186	            in_out += vl;
187	            size2 -= vl;
188	        }
189	    }
190	    else if(vlenb == 32)     //for VLEN=256
191	    {
192	        // load lookup_table into registers
193	        NDS_VEC_VSETVLI(vl, 256, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);  //lookup_table size is 256
194	        NDS_VEC_VLB_V(NDS_VEC_V0, lookup_table);    //v0~v7
195	
196	        while(size2 > 0)
197	        {
198	            NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
199	            NDS_VEC_VLB_V(NDS_VEC_V8, in_out);

