24	//// Basic Operation Functions
25	
26	void riscv_nn_add_s8_sym(const q7_t * in_vec1,
27	                        const q7_t * in_vec2,
28	                        const int16_t * scale1,
29	                        const int16_t * scale2,
30	                        const uint32_t size,
31	                        const uint16_t pre_rshift,
32	                        const uint16_t out_scale,
33	                        const uint16_t post_rshift,
34	                        q7_t * out_vec)
35	{
36	#ifdef ENA_EMPTY_FUN
37	    //empty body
38	#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_INTRINSIC)
39	    long vl, loop_cnt = size;
40	    while(loop_cnt > 0)
41	    {
42	        vl = __riscv_vsetvl_e8m2(loop_cnt);
43	        vint8m2_t va_i8m2 = __riscv_vle8_v_i8m2(in_vec1, vl);
44	        vint8m2_t vb_i8m2 = __riscv_vle8_v_i8m2(in_vec2, vl);
45	        vl = __riscv_vsetvl_e16m4(loop_cnt);
46	        vint16m4_t va_i16m4 = __riscv_vsext_vf2(va_i8m2, vl);
47	        vint16m4_t vb_i16m4 = __riscv_vsext_vf2(vb_i8m2, vl);
48	
49	        //*in_vec1 * *scale1
50	        vint16m4_t vas_i16m4 = __riscv_vle16_v_i16m4(scale1, vl);
51	        vint32m8_t vc_i32m8 = __riscv_vwmul(va_i16m4, vas_i16m4, vl);
52	        //*in_vec2 * *scale2
53	        vint16m4_t vbs_i16m4 = __riscv_vle16_v_i16m4(scale2, vl);
54	        vc_i32m8 = __riscv_vwmacc(vc_i32m8, vb_i16m4, vbs_i16m4, vl);
55	
56	        //sum up two multiplication results
57	        vl = __riscv_vsetvl_e32m8(loop_cnt);
58	        //acc = acc >> pre_rshift
59	        vc_i32m8 = __riscv_vsra(vc_i32m8, pre_rshift, vl);
60	        //acc = acc * out_scale
61	        vc_i32m8 = __riscv_vmul(vc_i32m8, out_scale, vl);
62	        //acc = acc >> out_shift
63	        vc_i32m8 = __riscv_vsra(vc_i32m8, post_rshift, vl);
64	        //saturation
65	        vl = __riscv_vsetvl_e16m4(loop_cnt);
66	        vint16m4_t vc_i16m4 = __riscv_vnclip(vc_i32m8, 0, __RISCV_VXRM_RNU, vl);
67	        vl = __riscv_vsetvl_e8m2(loop_cnt);
68	        vint8m2_t vc_i8m2 = __riscv_vnclip(vc_i16m4, 0, __RISCV_VXRM_RNU, vl);
69	        //store results
70	        __riscv_vse8(out_vec, vc_i8m2, vl);
71	
72	        //update counter and bump pointers
73	        loop_cnt -= vl;
74	        in_vec1 += vl;
75	        in_vec2 += vl;
76	        scale1 += vl;
77	        scale2 += vl;
78	        out_vec += vl;
79	    }
80	#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100)
81	    long vl, loop_cnt = size;
82	    while(loop_cnt > 0)
83	    {
84	        NDS_VEC_VSETVLI_E16_M4(vl, loop_cnt);
85	        NDS_VEC_VLB_V(NDS_VEC_V24, in_vec1);
86	        NDS_VEC_VLB_V(NDS_VEC_V28, in_vec2);
87	        NDS_VEC_VSEXT_VF2(NDS_VEC_V0, NDS_VEC_V24);
88	        NDS_VEC_VSEXT_VF2(NDS_VEC_V4, NDS_VEC_V28)  ;
89	
90	        //*in_vec1 * *scale1
91	        NDS_VEC_VLH_V(NDS_VEC_V8, scale1);
92	        NDS_VEC_VWMUL_VV(NDS_VEC_V16, NDS_VEC_V0, NDS_VEC_V8);
93	        //*in_vec2 * *scale2
94	        NDS_VEC_VLH_V(NDS_VEC_V12, scale2);
95	        NDS_VEC_VWMACC_VV(NDS_VEC_V16, NDS_VEC_V4, NDS_VEC_V12);
96	
97	        //sum up two multiplication results
98	        NDS_VEC_VSETVLI_E32_M8(vl, loop_cnt);
99	        //acc = acc >> pre_rshift
100	        NDS_VEC_VSRA_VX(NDS_VEC_V16, NDS_VEC_V16, pre_rshift);
101	        //acc = acc * out_scale
102	        NDS_VEC_VMUL_VX(NDS_VEC_V16, NDS_VEC_V16, out_scale);
103	        //acc = acc >> out_shift
104	        NDS_VEC_VSRA_VX(NDS_VEC_V16, NDS_VEC_V16, post_rshift);
105	        //saturation
106	        NDS_VEC_VSETVLI_E16_M4(vl, loop_cnt);
107	        NDS_VEC_VNCLIP_WI(NDS_VEC_V16, NDS_VEC_V16, 0);
108	        NDS_VEC_VSETVLI_E8_M2(vl, loop_cnt);
109	        NDS_VEC_VNCLIP_WI(NDS_VEC_V16, NDS_VEC_V16, 0);
110	        //store results
111	        NDS_VEC_VSB_V(NDS_VEC_V16, out_vec);
112	
113	        //update counter and bump pointers
114	        loop_cnt -= vl;
115	        in_vec1 += vl;
116	        in_vec2 += vl;
117	        scale1 += vl;
118	        scale2 += vl;
119	        out_vec += vl;
120	    }
121	#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION == 80)
122	    long vl, loop_cnt = size;
123	    while(loop_cnt > 0)
124	    {
125	        NDS_VEC_VSETVLI_E16_M4(vl, loop_cnt);
126	        NDS_VEC_VLB_V(NDS_VEC_V0, in_vec1);
127	        NDS_VEC_VLB_V(NDS_VEC_V4, in_vec2);
128	
129	        //*in_vec1 * *scale1
130	        NDS_VEC_VLH_V(NDS_VEC_V8, scale1);
131	        NDS_VEC_VWMUL_VV(NDS_VEC_V16, NDS_VEC_V0, NDS_VEC_V8);
132	        //*in_vec2 * *scale2
133	        NDS_VEC_VLH_V(NDS_VEC_V12, scale2);
134	        NDS_VEC_VWMACC_VV(NDS_VEC_V16, NDS_VEC_V4, NDS_VEC_V12);
135	
136	        //sum up two multiplication results
137	        NDS_VEC_VSETVLI_E32_M8(vl, loop_cnt);
138	        //acc = acc >> pre_rshift
139	        NDS_VEC_VSRA_VX(NDS_VEC_V16, NDS_VEC_V16, pre_rshift);
140	        //acc = acc * out_scale
141	        NDS_VEC_VMUL_VX(NDS_VEC_V16, NDS_VEC_V16, out_scale);
142	        //acc = acc >> out_shift
143	        NDS_VEC_VSRA_VX(NDS_VEC_V16, NDS_VEC_V16, post_rshift);
144	        //saturation
145	        NDS_VEC_VMAX_VX(NDS_VEC_V16, NDS_VEC_V16, 0xffffff80);
146	        NDS_VEC_VMIN_VX(NDS_VEC_V16, NDS_VEC_V16, 0x0000007f);
147	        //store results
148	        NDS_VEC_VSB_V(NDS_VEC_V16, out_vec);
149	
150	        //update counter and bump pointers
